  cursor: {{ result.cursor }}{% if result.exitCode != blank %}
  exitCode: {{ result.exitCode }}{% endif %}{% if result.signal %}
  signal: {{ result.signal }}{% endif %}{% if result.truncated %}
  outputHistoryTruncated: true{% endif %}{% for event in result.events %}{% if event.kind == 'output' %}

[{{ event.stream }} cursor={{ event.cursor }}]
